public class SynchronizationDemo {
    private int count = 0;
    synchronized void increment() { count++; }
    public static void main(String[] args) throws InterruptedException {
        SynchronizationDemo demo = new SynchronizationDemo();
        Thread t1 = new Thread(() -> { for (int i = 0; i < 1000; i++) demo.increment(); });
        Thread t2 = new Thread(() -> { for (int i = 0; i < 1000; i++) demo.increment(); });
        t1.start(); t2.start();
        t1.join(); t2.join();
        System.out.println("Count: " + demo.count);
    }
}

public class RaceConditionDemo {
    private int count = 0;
    void unsafeIncrement() { count++; } // not atomic
    public static void main(String[] args) throws InterruptedException {
        RaceConditionDemo demo = new RaceConditionDemo();
        Thread t1 = new Thread(() -> { for (int i = 0; i < 1000; i++) demo.unsafeIncrement(); });
        Thread t2 = new Thread(() -> { for (int i = 0; i < 1000; i++) demo.unsafeIncrement(); });
        t1.start(); t2.start();
        t1.join(); t2.join();
        System.out.println("Expected 2000, got: " + demo.count);
    }
}

public class DeadlockDemo {
    private final Object lockA = new Object();
    private final Object lockB = new Object();
    public static void main(String[] args) {
        DeadlockDemo demo = new DeadlockDemo();
        Thread t1 = new Thread(() -> {
            synchronized (demo.lockA) {
                try { Thread.sleep(50); } catch (InterruptedException e) {}
                synchronized (demo.lockB) { System.out.println("T1 done"); }
            }
        });
        Thread t2 = new Thread(() -> {
            synchronized (demo.lockB) {
                try { Thread.sleep(50); } catch (InterruptedException e) {}
                synchronized (demo.lockA) { System.out.println("T2 done"); }
            }
        });
        t1.start(); t2.start();
        System.out.println("Potential deadlock scenario started");
    }
}

