import java.util.*;
import java.util.stream.*;

// Illustrative Spring-style patterns without Spring dependency
record User(Long id, String name, boolean active) {}

class UserRepository {
    List<User> users = List.of(new User(1L, "Ravi", true), new User(2L, "Priya", false));
    Optional<User> findById(Long id) {
        return users.stream().filter(u -> u.id().equals(id)).findFirst();
    }
}

class UserService {
    private final UserRepository repo = new UserRepository();
    String getActiveUserName(Long id) {
        return repo.findById(id)
            .filter(User::active)
            .map(User::name)
            .orElse("Not found or inactive");
    }
}

public class SpringBootJava8Demo {
    public static void main(String[] args) {
        UserService svc = new UserService();
        System.out.println(svc.getActiveUserName(1L));
        System.out.println(svc.getActiveUserName(2L));
    }
}
